 */
int process_protocol_message(const char* msg_body, int body_len, 
                            char* param_buffer, int buffer_size)
{
    /* Validate input parameters */
    if (msg_body == NULL) {
        /* Invalid message body pointer */
        return -1;
    }

    if (param_buffer == NULL) {
        /* Invalid destination buffer pointer */
        return -1;
    }

    if (buffer_size <= 0) {
        /* Invalid buffer size */
        return -1;
    }

    if (body_len < 0) {
        /* Invalid message length */
        return -1;
    }

    /* Check if message body is empty */
    if (body_len == 0) {
        /* Empty message - set buffer to empty string */
        param_buffer[0] = '\0';
        return 0;
    }

    /* Calculate safe copy length:
       - We need space for null terminator, so maximum copy is buffer_size - 1
       - We can only copy up to body_len bytes
       - Use the smaller of these two values
    */
    size_t safe_copy_len = (size_t)(buffer_size - 1);

    /* Ensure we don't copy more than available message data */
    if ((size_t)body_len < safe_copy_len) {
        safe_copy_len = (size_t)body_len;
    }

    /* Check if we have anything to copy */
    if (safe_copy_len == 0) {
        /* Buffer too small for even null terminator (buffer_size == 1) */
        param_buffer[0] = '\0';
        return -1;
    }

    /* Check if buffer is too small to prevent overflow */
    size_t actual_strlen = strnlen(msg_body, safe_copy_len);
    if (actual_strlen >= (size_t)buffer_size) {
        /* Buffer too small to hold the string */
        return -1;
    }

    /* Perform safe memory copy using memmove to handle overlapping memory */
    memmove(param_buffer, msg_body, safe_copy_len);

    /* Ensure null termination */
    param_buffer[safe_copy_len] = '\0';

    /* Optional: Check if the source string was properly terminated within bounds
       If the source string has a null terminator within safe_copy_len,
       we might want to adjust our copy length to stop at the terminator.
    */
    if (actual_strlen < safe_copy_len) {
        /* Source has null terminator within bounds - adjust */
        param_buffer[actual_strlen] = '\0';
    }

    /* Success */
    return 0;
}

