 */
void test_process_protocol_message(void)
{
    char buffer[128];
    const char* test_msg = "param_value";
    int result;

    /* Test 1: Normal operation */
    result = process_protocol_message(test_msg, strlen(test_msg), buffer, sizeof(buffer));
    assert(result == 0);
    assert(strcmp(buffer, "param_value") == 0);

    /* Test 2: Buffer exactly fits string */
    char small_buffer[12]; /* "param_value" + null terminator */
    result = process_protocol_message(test_msg, strlen(test_msg), small_buffer, sizeof(small_buffer));
    assert(result == 0);
    assert(strcmp(small_buffer, "param_value") == 0);

    /* Test 3: Buffer too small */
    char tiny_buffer[5];
    result = process_protocol_message(test_msg, strlen(test_msg), tiny_buffer, sizeof(tiny_buffer));
    assert(result == -1); /* Should return -1 for small buffer */

    /* Test 4: Empty message */
    result = process_protocol_message("", 0, buffer, sizeof(buffer));
    assert(result == 0);
    assert(buffer[0] == '\0');

    /* Test 5: NULL message body */
    result = process_protocol_message(NULL, 10, buffer, sizeof(buffer));
    assert(result == -1);

    /* Test 6: NULL buffer */
    result = process_protocol_message(test_msg, strlen(test_msg), NULL, sizeof(buffer));
    assert(result == -1);

    /* Test 7: Invalid buffer size */
    result = process_protocol_message(test_msg, strlen(test_msg), buffer, 0);
    assert(result == -1);

    /* Test 8: Invalid message length */
    result = process_protocol_message(test_msg, -1, buffer, sizeof(buffer));
    assert(result == -1);

    /* Test 9: Message with embedded null */
    const char* embedded_null = "hello\0world";
    result = process_protocol_message(embedded_null, 11, buffer, sizeof(buffer));
    assert(result == 0);
    assert(strcmp(buffer, "hello") == 0); /* Should stop at first null */

    printf("All tests passed!\n");
}

